# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from web3 import Web3
from flask import Flask, request, jsonify

app = Flask(__name__)

# Ethereum node endpoint
ethereum_endpoint = "YOUR_ENDPOINT"

# Initialize Web3 provider
w3 = Web3(Web3.HTTPProvider(ethereum_endpoint))

@app.route("/authenticate", methods=["POST"])
def authenticate():
    try:
        # Get signed message and signature from request
        signed_message = request.json["message"]
        signature = request.json["signature"]

        # Recover the address from the signature
        address = w3.eth.account.recover_message(signed_message, signature)

        # Return the authenticated address
        return jsonify({"address": address}), 200

    except Exception as e:
        # Handle error
        return jsonify({"error": str(e)}), 400

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)